create extension if not exists pgcrypto;
do $$ begin create type public.project_research_type as enum ('CTI','AI_SECURITY','OSINT','DFIR','MALWARE','VULN_RESEARCH','GEOPOLITICAL'); exception when duplicate_object then null; end $$;
do $$ begin create type public.project_priority as enum ('LOW','MEDIUM','HIGH','CRITICAL'); exception when duplicate_object then null; end $$;
create or replace function public.set_updated_at() returns trigger language plpgsql security definer set search_path = public as $$ begin new.updated_at = now(); return new; end; $$;
create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade, display_name text check (char_length(display_name) <= 120), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create or replace function public.handle_new_user() returns trigger language plpgsql security definer set search_path = public as $$ begin insert into public.profiles (id, display_name) values (new.id, left(coalesce(new.raw_user_meta_data->>'display_name',''),120)) on conflict (id) do nothing; return new; end; $$;
drop trigger if exists on_auth_user_created on auth.users; create trigger on_auth_user_created after insert on auth.users for each row execute function public.handle_new_user();
create table if not exists public.projects (id uuid primary key default gen_random_uuid(), owner_id uuid not null references auth.users(id) on delete cascade, name text not null check (char_length(trim(name)) between 2 and 120), description text not null default '' check (char_length(description) <= 2000), research_type public.project_research_type not null, priority public.project_priority not null default 'MEDIUM', tags text[] not null default '{}' check (array_length(tags,1) is null or array_length(tags,1) <= 12), created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique(owner_id, name));
create index if not exists projects_owner_id_idx on public.projects(owner_id); create index if not exists projects_updated_at_idx on public.projects(updated_at desc); create index if not exists projects_research_type_idx on public.projects(research_type); create index if not exists projects_priority_idx on public.projects(priority);
drop trigger if exists profiles_set_updated_at on public.profiles; create trigger profiles_set_updated_at before update on public.profiles for each row execute function public.set_updated_at();
drop trigger if exists projects_set_updated_at on public.projects; create trigger projects_set_updated_at before update on public.projects for each row execute function public.set_updated_at();
alter table public.profiles enable row level security; alter table public.projects enable row level security;
drop policy if exists "profiles select own" on public.profiles; create policy "profiles select own" on public.profiles for select to authenticated using (auth.uid() is not null and auth.uid() = id);
drop policy if exists "profiles insert own" on public.profiles; create policy "profiles insert own" on public.profiles for insert to authenticated with check (auth.uid() is not null and auth.uid() = id);
drop policy if exists "profiles update own" on public.profiles; create policy "profiles update own" on public.profiles for update to authenticated using (auth.uid() is not null and auth.uid() = id) with check (auth.uid() is not null and auth.uid() = id);
drop policy if exists "profiles delete own" on public.profiles; create policy "profiles delete own" on public.profiles for delete to authenticated using (auth.uid() is not null and auth.uid() = id);
drop policy if exists "projects select own" on public.projects; create policy "projects select own" on public.projects for select to authenticated using (auth.uid() is not null and auth.uid() = owner_id);
drop policy if exists "projects insert own" on public.projects; create policy "projects insert own" on public.projects for insert to authenticated with check (auth.uid() is not null and auth.uid() = owner_id);
drop policy if exists "projects update own" on public.projects; create policy "projects update own" on public.projects for update to authenticated using (auth.uid() is not null and auth.uid() = owner_id) with check (auth.uid() is not null and auth.uid() = owner_id);
drop policy if exists "projects delete own" on public.projects; create policy "projects delete own" on public.projects for delete to authenticated using (auth.uid() is not null and auth.uid() = owner_id);
